mapper.select:
SELECT *
FROM (
    SELECT u.*,
           ROW_NUMBER() OVER (PARTITION BY u.user_id ORDER BY u.update_time DESC) AS rn
    FROM user_task_instance u
    WHERE u.status > 0
      AND u.user_id IN

          #{uid}

) t
WHERE t.rn <= #{perUserLimit}
ORDER BY t.user_id ASC, t.update_time DESC
LIMIT #{totalLimit}
